// ✅ Safe way to read current FOV:
var fov = core.getStelProperty('StelMovementMgr.currentFov');

// ❌ May not work:
// var fov = StelMovementMgr.getCurrentFov();

// ✅ Safe way to write (set) values:
StelMovementMgr.zoomTo(60.0, 1.0);
StelMovementMgr.setFlagTracking(true);

// Enable tracking of the selected object
StelMovementMgr.setFlagTracking(true);

// Disable tracking
StelMovementMgr.setFlagTracking(false);

// Read tracking state (alternative method)
var isTracking = core.getStelProperty('StelMovementMgr.tracking');
core.debug("Tracking is " + (isTracking ? "on" : "off"));

// Alternative method (recommended):
var isTracking = core.getStelProperty('StelMovementMgr.tracking');
core.debug("Tracking is " + (isTracking ? "on" : "off"));

// Lock view to equatorial coordinates (sky stays fixed)
StelMovementMgr.setFlagLockEquPos(true);

// Unlock (allow Earth rotation effect)
StelMovementMgr.setFlagLockEquPos(false);

// Switch to equatorial mount
StelMovementMgr.setEquatorialMount(true);

// Switch to alt-azimuthal mount
StelMovementMgr.setEquatorialMount(false);

// Read mount mode state (alternative method)
var isEquatorial = core.getStelProperty('StelMovementMgr.equatorialMount');
core.debug("Equatorial mount is " + (isEquatorial ? "on" : "off"));

// Set to equatorial mode
StelMovementMgr.setMountMode(1);

// Set to galactic mode
StelMovementMgr.setMountMode(2);

// Instantly zoom in to 10 degrees
StelMovementMgr.setFov(10.0);

// Instantly zoom out to 90 degrees
StelMovementMgr.setFov(90.0);

// Read current FOV (alternative method)
var currentFov = core.getStelProperty('StelMovementMgr.currentFov');
core.debug("Current FOV: " + currentFov);

// Alternative method (recommended):
var fov = core.getStelProperty('StelMovementMgr.currentFov');
core.debug("Current FOV: " + fov + "°");

// Smooth zoom to 5 degrees over 2 seconds
StelMovementMgr.zoomTo(5.0, 2.0);

// Smooth zoom to 90 degrees over 1 second
StelMovementMgr.zoomTo(90.0, 1.0);

// Instant zoom
StelMovementMgr.zoomTo(60.0, 0);

// Start zooming in
StelMovementMgr.zoomIn(true);
core.wait(2);
// Stop zooming
StelMovementMgr.zoomIn(false);

// Start zooming out
StelMovementMgr.zoomOut(true);
core.wait(2);
StelMovementMgr.zoomOut(false);

// Select an object and zoom in
core.selectObjectByName("Mars", true);
StelMovementMgr.autoZoomIn(1.5, true);

// Zoom out to see the satellite system of the selected object
StelMovementMgr.autoZoomOut(1.0, false);

// Zoom out fully to the initial view
StelMovementMgr.autoZoomOut(2.0, true);

// Limit FOV to 180° for planetarium
StelMovementMgr.setUserMaxFov(180.0);

// No artificial limit (up to projection max)
StelMovementMgr.setUserMaxFov(360.0);

// Faster auto-moves
StelMovementMgr.setAutoMoveDuration(0.8);

// Slower, more cinematic moves
StelMovementMgr.setAutoMoveDuration(3.0);

// Set the current view as the new default view
StelMovementMgr.setInitViewDirectionToCurrent();
core.debug("New default view direction saved");

// Get the Mars object and center the view on it
var mars = core.getObjectInfo("Mars");
StelMovementMgr.moveToObject(mars, 2.0, 1);

// Move to the celestial equator at 0h RA, 0° Dec
var aim = core.vec3d("0h", "0d");
var up = core.vec3d(0, 0, 1);
StelMovementMgr.moveToJ2000(aim, up, 2.0, 0);

// Switch to Alt-Azimuth mode first
StelMovementMgr.setEquatorialMount(false);

// Move to the zenith
var aim = core.vec3d(0, 0, 1);
var up = core.vec3d(0, 0, 1);
StelMovementMgr.moveToAltAzi(aim, up, 1.5, 0);

// Start turning right for 1 second
StelMovementMgr.turnRight(true);
core.wait(1);
StelMovementMgr.turnRight(false);

StelMovementMgr.turnLeft(true);
core.wait(1);
StelMovementMgr.turnLeft(false);

StelMovementMgr.turnUp(true);
core.wait(1);
StelMovementMgr.turnUp(false);

StelMovementMgr.turnDown(true);
core.wait(1);
StelMovementMgr.turnDown(false);

// Look east at the current altitude
StelMovementMgr.lookEast(false);

// Look east at the horizon
StelMovementMgr.lookEast(true);

// Shift the view down by 20% over 2 seconds
StelMovementMgr.moveViewport(0, 20, 2.0);

// Reset the viewport instantly
StelMovementMgr.moveViewport(0, 0, 0);

// May not work reliably:
// var dir = core.vec3d("0h", "0d");
// StelMovementMgr.setViewDirectionJ2000(dir);

// Use moveToJ2000 instead for reliable movement:
StelMovementMgr.moveToJ2000(dir, core.vec3d(0,0,1), 1.0, 0);

// May not work reliably:
// var up = core.vec3d(0, 0, 1);
// StelMovementMgr.setViewUpVector(up);

// Inhibit automatic movements (e.g., for a planetarium show)
StelMovementMgr.setInhibitAllAutomoves(true);

// Allow automatic movements
StelMovementMgr.setInhibitAllAutomoves(false);
